export declare const PROMPTS_README_MD = "# Prompts Recomendados SDD\n\nUse estes prompts para acelerar workflows no agente sem perder padrao.\n\n## Ordem recomendada para material bruto\n1. `00-comece-por-aqui.md`\n2. `01-ingestao-deposito.md`\n3. `02-normalizar-planejamento.md`\n4. `03-execucao-feature.md`\n5. `04-consolidacao-finalize.md`\n\nRegra: os prompts guiam o agente, mas o estado can\u00F4nico continua em `.sdd/state/*.yaml`.\n";
export declare const PROMPT_00_COMECE_POR_AQUI_MD = "# Comece Por Aqui (Primeiro Uso)\n\nSe voce nunca usou o OpenSDD, siga exatamente esta ordem.\n\n## 1) Instalar e iniciar no projeto\n\nNo terminal, dentro da pasta do seu projeto:\n\n```bash\nopensdd install --tools none --lang pt-BR --layout pt-BR\nopensdd sdd init --frontend --lang pt-BR --layout pt-BR\nopensdd sdd init-context\nopensdd sdd check --render\nopensdd sdd onboard system\n```\n\n## 2) Entender as pastas principais\n\n- `.sdd/deposito/`: onde voce coloca material bruto (PRD, wireframe, historias, referencias).\n- `.sdd/state/`: fonte can\u00F4nica (verdade oficial em YAML).\n- `.sdd/core/`: visao humana gerada automaticamente.\n- `.sdd/planejamento/` ou `.sdd/pendencias/`: backlog, progresso, fila de finalize.\n- `.sdd/execucao/` ou `.sdd/active/`: pacote de trabalho por FEAT.\n- `.sdd/arquivados/` ou `.sdd/archived/`: workspaces finalizados.\n\n## 3) Tenho PRD/wireframe/historias. E agora?\n\n1. Copie os arquivos para `.sdd/deposito/` (subpastas corretas).\n2. Rode:\n\n```bash\nopensdd sdd ingest-deposito --title \"Planejamento inicial do sistema\"\n```\n\n3. Revise:\n\n```bash\nopensdd sdd check --render\nopensdd sdd next\n```\n\nResultado esperado:\n- fontes indexadas em `.sdd/state/source-index.yaml`\n- EPIC (ou RAD legado) criado/reaproveitado\n- FEATs geradas no backlog\n- primeira FEAT pronta iniciada automaticamente (quando possivel)\n\n## 4) Como executar uma feature\n\n```bash\nopensdd sdd start FEAT-0001 --fluxo padrao\nopensdd sdd context FEAT-0001\nopensdd sdd frontend-impact FEAT-0001 --status required --reason \"Nova rota e novos componentes de UI\"\n```\n\nImplemente e atualize o pacote da FEAT:\n- `1-especificacao.md` (ou `1-spec.md`)\n- `2-planejamento.md` (ou `2-plan.md`)\n- `3-tarefas.md` (ou `3-tasks.md`)\n- `4-historico.md` (ou `4-changelog.md`)\n\n## 5) Como finalizar sem perder contexto\n\n```bash\nopensdd archive <change-name>\nopensdd sdd finalize --ref FEAT-0001\nopensdd sdd check --render\nopensdd sdd onboard system\n```\n\nRegra de ouro:\n- Uma FEAT so esta realmente pronta depois da consolidacao documental.\n\n## 6) Historia de uso curta (Marina)\n\nMarina colocou PRD + wireframe em `.sdd/deposito/`.\nEla rodou `opensdd sdd ingest-deposito` e recebeu um EPIC (RAD) + FEATs prontas para iniciar.\nComecou pela FEAT prioritaria com `opensdd sdd start FEAT-0001`.\nAntes de codar, rodou `opensdd sdd context FEAT-0001`.\nAo terminar, arquivou a change e executou `opensdd sdd finalize --ref FEAT-0001`.\nResultado: backlog atualizado, docs sincronizadas e proxima FEAT liberada sem adivinhacao.\n\n## 7) Comandos essenciais (resumo)\n\n- `opensdd sdd onboard system`: entender o estado atual.\n- `opensdd sdd ingest-deposito`: transformar material bruto em trilha executavel.\n- `opensdd sdd next`: ver o que pode comecar agora.\n- `opensdd sdd start FEAT-0001`: abrir execucao da feature.\n- `opensdd sdd context FEAT-0001`: gerar contexto focado.\n- `opensdd sdd frontend-impact FEAT-0001 --status required|none --reason \"...\"`: declarar impacto frontend.\n- `opensdd sdd finalize --ref FEAT-0001`: consolidar memoria e concluir.\n";
export declare const PROMPT_01_INGESTAO_DEPOSITO_MD = "# Prompt: Ingestao de Deposito\n\nUse as skills:\n- source-intake-sdd\n- business-extractor-sdd\n- frontend-extractor-sdd\n- planning-normalizer-sdd\n\nObjetivo:\n1. Varrer `.sdd/deposito/`.\n2. Atualizar `.sdd/state/source-index.yaml`.\n3. Consolidar contexto can\u00F4nico (`architecture`, `service-catalog`, `tech-stack`, `integration-contracts`, frontend quando habilitado).\n4. Gerar trilha execut\u00E1vel (EPIC, com suporte a RAD legado, + FEATs) com rastreabilidade de origem.\n\nSaida obrigatoria:\n- resumo das fontes lidas;\n- IDs criados/atualizados (RAD/FEAT/FGAP/INS quando houver ambiguidade);\n- proximos comandos CLI recomendados.\n";
export declare const PROMPT_02_NORMALIZAR_PLANEJAMENTO_MD = "# Prompt: Normalizar Planejamento\n\nObjetivo:\nTransformar material consolidado em plano execut\u00E1vel com depend\u00EAncias claras.\n\nInstrucoes:\n1. Parta de `.sdd/state/source-index.yaml` e `.sdd/core/*.md`.\n2. Proponha EPICs (ou RADs) e FEATs com nomes claros em portugues.\n3. Defina dependencias (`blocked_by`) e conflitos (`lock_domains`).\n4. Liste onde pode paralelizar.\n5. Termine com checklist de consolidacao documental por feature.\n";
export declare const PROMPT_03_EXECUCAO_FEATURE_MD = "# Prompt: Execucao de Feature\n\nObjetivo:\nExecutar uma FEAT sem perder rastreabilidade.\n\nInstrucoes:\n1. Rode `opensdd sdd context FEAT-0001`.\n2. Atualize `.sdd/execucao|active/FEAT-0001/` (spec/plano/tarefas/historico).\n3. Implemente.\n4. Atualize docs can\u00F4nicas afetadas.\n5. Declare impacto frontend com `opensdd sdd frontend-impact FEAT-0001 ...`.\n6. Finalize com `opensdd archive <change-name>` e `opensdd sdd finalize --ref FEAT-0001`.\n";
export declare const PROMPT_04_CONSOLIDACAO_FINALIZE_MD = "# Prompt: Consolidacao e Finalize\n\nObjetivo:\nFechar uma feature com memoria operacional completa.\n\nChecklist:\n1. Revisar diff t\u00E9cnico da FEAT.\n2. Atualizar documenta\u00E7\u00E3o central (`README.md`, `.sdd/AGENT.md`, `.sdd/core/*.md`, `AGENTS.md`, `AGENT.md`).\n3. Garantir registro de gaps/decisoes de frontend quando aplicavel.\n4. Declarar impacto frontend com `opensdd sdd frontend-impact FEAT-0001 --status required|none --reason \"...\"`.\n5. Rodar `opensdd sdd check --render`.\n6. Rodar `opensdd sdd finalize --ref FEAT-0001` e reportar docs atualizados.\n";
export declare const TEMPLATE_1_SPEC_MD = "# Especificacao: [NOME_DA_ENTREGA]\n\n<!-- Instrucao do sistema:\n- Contem: Dor real e objetivo descritos com clareza.\n- Proibido: [\"TODO\", \"(preencher\", \"Descrever o\", ou repeticoes do titulo]\n- Qualidade minima exigida: As secoes 'Resumo da Entrega', 'Problema' e 'Objetivo' devem possuir ao menos 3 sentencas substanciais de contexto.\n-->\n\n## Resumo da Entrega\n- Entrega:\n- Fluxo: direto|padrao|rigoroso\n- Origem: INS/DEB/RAD/FEAT direta\n\n## Problema\nDescreva a dor real que esta entrega resolve.\n\n## Objetivo\n- Descreva detalhadamente o resultado esperado.\n- Adicione contexto de negocio ou motivacao clara.\n- Liste impactos positivos para usuario ou sistema.\n\n## Escopo\n- [ ] Item 1\n- [ ] Item 2\n\n## Fora do Escopo\n- [ ] Item 1\n- [ ] Item 2\n\n## Valor Esperado\n- Indicador:\n- Meta:\n\n## Regras de Negocio\n- [ ] Regra 1\n- [ ] Regra 2\n\n## Criterios de Aceite\n- CA-01:\n- CA-02:\n- CA-03:\n\n## Declaracao de Impacto Frontend\n- Status (`unknown|none|required`):\n- Justificativa:\n- Comando: `opensdd sdd frontend-impact FEAT-0001 --status required|none --reason \"...\"`\n\n## Referencias\n- FEAT:\n- EPIC (antigo RAD):\n- FGAP:\n- ADR:\n";
export declare const TEMPLATE_2_PLAN_MD = "# Planejamento: [NOME_DA_ENTREGA]\n\n<!-- Instrucao do sistema:\n- Contem: Detalhes concretos de implementacao e fatiamento tecnico.\n- Proibido: [\"TODO\", \"(preencher\", descricoes vazias sem aprofundamento tecnico]\n- Qualidade minima exigida: A secao 'Abordagem Tecnica' deve explicar COMO a feature sera resolvida.\n-->\n\n## Abordagem Tecnica\nDescreva como a solucao sera implementada.\n\n## Fatias Executaveis\n- F1:\n- F2:\n- F3:\n\n## Paralelizacao\n- Pode rodar em paralelo:\n- Depende de:\n\n## Impacto Arquitetural\n- Servicos afetados:\n- Dados afetados:\n\n## Contratos Afetados\n- APIs e contratos consumidos/providos:\n\n## Impacto Frontend\n- Rotas afetadas:\n- Gaps criados ou resolvidos:\n- Decisoes de frontend relevantes:\n- Declaracao obrigatoria: `opensdd sdd frontend-impact FEAT-0001 --status required|none --reason \"...\"`\n\n## Skills e Bundles\n- Skills consultadas:\n- Bundles sugeridos:\n\n## Regra de Interseccao\n- Dividas tecnicas relacionadas:\n- Frontend gaps relacionados:\n- Documentacao que precisa mudar:\n";
export declare const TEMPLATE_3_TASKS_MD = "# Checklist de Tarefas: [NOME_DA_ENTREGA]\n\n<!-- Instrucao do sistema:\n- Contem: Lista acionavel de tarefas sequenciais.\n- Proibido: [\"TODO\", \"(preencher\"]\n- Qualidade minima exigida: Passos realistas de implementacao desdobrados do plano.\n-->\n\n## Passos de Implementacao\n- [ ] Entender o contexto com `opensdd sdd context FEAT-0001`\n- [ ] Ajustar ou confirmar o plano tecnico\n- [ ] Implementar o codigo\n- [ ] Validar comportamento e testes\n- [ ] Declarar impacto frontend com `opensdd sdd frontend-impact FEAT-0001 --status required|none --reason \"...\"`\n\n## Consolidacao Obrigatoria\n- [ ] Atualizar `README.md`, `.sdd/AGENT.md`, `AGENTS.md`, `AGENT.md` e os arquivos de `.sdd/core/` afetados\n- [ ] Se impacto frontend=required, garantir FGAP aberto/atualizado antes do finalize\n- [ ] Registrar gaps de frontend criados ou resolvidos\n- [ ] Atualizar o changelog da feature\n- [ ] Arquivar a mudanca tecnica e executar `opensdd sdd finalize --ref FEAT-0001`\n\n## Definition of Done\n- [DOC] Documentacao central atualizada\n- [UI] Lacunas/decisoes de frontend registradas (quando aplicavel)\n- [ARQ] Change tecnica arquivada no OpenSpec\n- [MEM] Memoria consolidada com `opensdd sdd finalize --ref FEAT-0001`\n";
export declare const TEMPLATE_4_CHANGELOG_MD = "# Changelog de Arquitetura: [NOME_DA_FEATURE]\n\n<!-- Instrucao do sistema:\n- Contem: Registro concreto do que mudou ou foi resolvido.\n- Proibido: [\"TODO\", \"(preencher\", arquivos mockados sem mudanca real]\n- Qualidade minima exigida: Refletir a verdade do commit/implementacao.\n-->\n\n## Novas Entidades / Modelos\n-\n\n## Novas Rotas / Endpoints / Eventos\n-\n\n## Cobertura Frontend\n- Impacto declarado (`opensdd sdd frontend-impact`):\n- FGAPs criados/atualizados:\n\n## Mudancas Estruturais\n-\n\n## Documentos que Precisam Ser Atualizados\n-\n";
